#include <bits/stdc++.h>
using namespace std;
const int N=2e4+4;
int t,n,a[N],q,l,r,f[N][15],last[15];
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
            scanf("%d",&a[i]);
        for(int i=1;i<=13;i++)
            last[i]=n+1;
        memset(f,63,sizeof(f));
        for(int i=n;i;i--){
            f[i][0]=last[a[i]];
            last[a[i]]=i;
            for(int j=1;j<15 && f[i][j-1]<n;j++)
                f[i][j]=f[f[i][j-1]+1][j-1];
        }
        scanf("%d",&q);
        while(q--){
            int l,r;
            scanf("%d%d",&l,&r);
            int p=l,sum=0;
            while(p<=r){
                for(int i=14;i>=0 && p<=r;i--)
                    if(f[p][i]<=r)
                        p=f[p][i]+1;
                if(p<=r)
                    p++,sum++;
            }
            printf("%d\n",sum);
        }
    }
    return 0;
}
